import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api";
import { LeftPanel } from "./RoleSelection.js";

function LoginForm({ role, onBack }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState("");
  const [sending, setSending] = useState(false);
  const [popup, setPopup] = useState(null);
  const navigate = useNavigate();

  const getRoleTitle = () => {
    const titles = {
      police: "Police Officer",
      forensic: "Forensic Officer",
      admin: "Administrator",
      lead: "Lead Investigator",
    };
    return titles[role] || "User";
  };

  const getRoleColor = () => {
    const colors = {
      police: "#3b82f6",
      forensic: "#f59e0b",
      admin: "#8b5cf6",
      lead: "#10b981",
    };
    return colors[role] || "#4f46e5";
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    try {
      const res = await api.post("/login", { email, password });

      console.log("LOGIN RESPONSE:", res.data); // 🔥 DEBUG

      // ✅ FORCE CHECK TOKEN
      if (res.data && res.data.token) {
        localStorage.setItem("token", res.data.token);
        localStorage.setItem("user", JSON.stringify(res.data.user));

        // 🔥 VERIFY STORAGE
        console.log("TOKEN AFTER SAVE:", localStorage.getItem("token"));

        navigate("/dashboard");
      } else {
        setError("Login failed: Token not received");
      }
    } catch (err) {
      console.error("LOGIN ERROR:", err);

      setError(
        err.response?.data?.message ||
          err.response?.data?.error ||
          "Login failed",
      );
    }
  };

  const handleForgotPassword = async () => {
    if (!email) {
      setError("Please enter your email address first");
      return;
    }

    setSending(true);
    setError("");

    try {
      const res = await fetch(
        "http://localhost:5000/password-reset-request-public",
        {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ email }),
        },
      );

      const data = await res.json();
      const adminName = data.adminName || "Admin";

      setPopup({
        message: `Your request has been sent to ${adminName} for password reset.`,
      });

      setTimeout(() => setPopup(null), 6000);
    } catch (err) {
      setPopup({
        message: "Your request has been sent to Admin for password reset.",
      });
      setTimeout(() => setPopup(null), 6000);
    } finally {
      setSending(false);
    }
  };

  return (
    <>
      <LeftPanel />
      <div className="right">
        <div className="formContainer">
          <button className="backButton" onClick={onBack}>
            <i className="bx bx-arrow-back"></i> Change Role
          </button>

          <header className="formHeader">
            <h2>Welcome Back</h2>
            <p>
              Sign in as{" "}
              <strong style={{ color: getRoleColor() }}>
                {getRoleTitle()}
              </strong>
            </p>
          </header>

          <div className="securityNotice">
            <i className="bx bx-shield-quarter"></i>
            <div>
              <strong>Secure Login</strong>
              <p>Your credentials are encrypted and protected</p>
            </div>
          </div>

          <form className="loginForm" onSubmit={handleSubmit}>
            <div className="inputGroup">
              <label>Email Address</label>
              <div className="inputWrapper">
                <input
                  type="email"
                  placeholder="your.email@agency.gov"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                />
                <i className="bx bx-envelope"></i>
              </div>
            </div>

            <div className="inputGroup">
              <label>Password</label>
              <div className="inputWrapper">
                <input
                  type={showPassword ? "text" : "password"}
                  placeholder="Enter your password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                />
                <i
                  className={showPassword ? "bx bx-eye" : "bx bx-eye-closed"}
                  onClick={() => setShowPassword(!showPassword)}
                ></i>
              </div>
            </div>

            {error && <p className="error">{error}</p>}

            <div className="formUtils">
              <label>
                <input type="checkbox" /> Remember me
              </label>
              <a
                href="#"
                onClick={(e) => {
                  e.preventDefault();
                  handleForgotPassword();
                }}
                style={{
                  opacity: sending ? 0.6 : 1,
                  pointerEvents: sending ? "none" : "auto",
                }}
              >
                {sending ? "Sending..." : "Forgot password?"}
              </a>
            </div>

            <button type="submit" className="submitBtn">
              Sign In Securely
            </button>
          </form>

          <footer className="formFooter">
            Need access? <a href="#">Contact administrator</a>
          </footer>
        </div>

        {popup && (
          <div className="adminRequestPopup">
            <h4>✓ Request Sent</h4>
            <p>{popup.message}</p>
          </div>
        )}
      </div>
    </>
  );
}

export default LoginForm;
